import React, { useState } from 'react';
import { Box, TextField, Button, List, ListItem, ListItemText, Paper, Typography } from '@mui/material';
import Navbar from '../components/Navbar';

const BGPchat = () => {
    const [messages, setMessages] = useState([]);
    const [currentMessage, setCurrentMessage] = useState('');

    const handleSendMessage = () => {
        if (currentMessage.trim() !== '') {
            setMessages([...messages, currentMessage]);
            setCurrentMessage('');
        }
    };

    const handleMessageChange = (event) => {
        setCurrentMessage(event.target.value);
    };

    const handleKeyPress = (event) => {
        if (event.key === 'Enter' && !event.shiftKey) {
            handleSendMessage();
            event.preventDefault();
        }
    };

    return (
        <div>
            <Navbar />
            <Box sx={{ display: 'flex', flexDirection: 'column', justifyContent: 'center', alignItems: 'center', height: '100vh', padding: 2 }}>
                <Typography variant="h4" gutterBottom>Chat Interface</Typography>
                <Paper style={{ width: '100%', maxHeight: 400, overflow: 'auto', marginBottom: 2 }}>
                    <List>
                        {messages.map((message, index) => (
                            <ListItem key={index}>
                                <ListItemText primary={message} />
                            </ListItem>
                        ))}
                    </List>
                </Paper>
                <Box
                    component="form"
                    sx={{
                        width: '100%',
                        display: 'flex',
                        alignItems: 'center'
                    }}
                    onSubmit={(e) => { e.preventDefault(); handleSendMessage(); }}
                >
                    <TextField
                        label="Type your message"
                        fullWidth
                        variant="outlined"
                        value={currentMessage}
                        onChange={handleMessageChange}
                        onKeyPress={handleKeyPress}
                        multiline
                        maxRows={4}
                    />
                    <Button variant="contained" color="primary" onClick={handleSendMessage} sx={{ marginLeft: 1 }}>
                        Send
                    </Button>
                </Box>
            </Box>
        </div>
    );
}

export default BGPchat;
